(("undefined"!=typeof globalThis?globalThis:self).makoChunk_antd=("undefined"!=typeof globalThis?globalThis:self).makoChunk_antd||[]).push([["22a9a66a"],{"22a9a66a":function(e,a,t){"use strict";t.d(a,"__esModule",{value:!0}),t.d(a,"texts",{enumerable:!0,get:function(){return o;}}),t("d79d39c5");let o=[{value:"Use when a container needs stronger visual emphasis without introducing business state semantics.",paraId:0,tocIndex:0},{value:"Suitable for login panels, recommendation cards, AI modules, and key CTA blocks.",paraId:0,tocIndex:0},{value:"As a decorative effect, it should not replace focus rings, validation borders, or status feedback.",paraId:0,tocIndex:0},{value:"Common props ref\uFF1A",paraId:1,tocIndex:6},{value:"Common props",paraId:2,tocIndex:6},{value:"Property",paraId:3,tocIndex:7},{value:"Description",paraId:3,tocIndex:7},{value:"Type",paraId:3,tocIndex:7},{value:"Default",paraId:3,tocIndex:7},{value:"Version",paraId:3,tocIndex:7},{value:"Global Config",paraId:4,tocIndex:7},{value:"children",paraId:3,tocIndex:7},{value:"Decorated content",paraId:3,tocIndex:7},{value:"ReactNode",paraId:3,tocIndex:7},{value:"-",paraId:3,tocIndex:7},{value:"6.4.0",paraId:3,tocIndex:7},{value:"\xd7",paraId:3,tocIndex:7},{value:"color",paraId:3,tocIndex:7},{value:"Beam color configuration. Supports a single color string or gradient stops. ",paraId:3,tocIndex:7},{value:"percent",paraId:3,tocIndex:7},{value:" uses the ",paraId:3,tocIndex:7},{value:"0 ~ 100",paraId:3,tocIndex:7},{value:" input range and BorderBeam reserves tail space for the transparent fade",paraId:3,tocIndex:7},{value:"string | { color: string; percent: number }[]",paraId:3,tocIndex:7},{value:"-",paraId:3,tocIndex:7},{value:"6.4.0",paraId:3,tocIndex:7},{value:"\xd7",paraId:3,tocIndex:7},{value:"outset",paraId:3,tocIndex:7},{value:"Outset distance of the beam layer from the container edge. Set to ",paraId:3,tocIndex:7},{value:"0",paraId:3,tocIndex:7},{value:" for clipped containers",paraId:3,tocIndex:7},{value:"number | string",paraId:3,tocIndex:7},{value:"-",paraId:3,tocIndex:7},{value:"6.4.0",paraId:3,tocIndex:7},{value:"\xd7",paraId:3,tocIndex:7},{value:"BorderBeam",paraId:5,tocIndex:10},{value:" treats the beam as a decorative effect. When ",paraId:5,tocIndex:10},{value:"prefers-reduced-motion: reduce",paraId:5,tocIndex:10},{value:" is active, the beam effect is hidden.",paraId:5,tocIndex:10},{value:"percent",paraId:6},{value:"color",paraId:6},{value:"percent",paraId:7,tocIndex:11},{value:" represents the authored stop position and accepts values from ",paraId:7,tocIndex:11},{value:"0",paraId:7,tocIndex:11},{value:" to ",paraId:7,tocIndex:11},{value:"100",paraId:7,tocIndex:11},{value:". BorderBeam maps those stops into the visible beam segment and reserves the trailing area for transparent fade-out so the moving tail stays visible.",paraId:7,tocIndex:11},{value:"BorderBeam",paraId:6},{value:"BorderBeam",paraId:8,tocIndex:12},{value:" needs to resolve the actual DOM node from ",paraId:8,tocIndex:12},{value:"children",paraId:8,tocIndex:12},{value:" and insert the beam layer into that node. Make sure the wrapped content is a native DOM element, or a React component that correctly forwards its ",paraId:8,tocIndex:12},{value:"ref",paraId:8,tocIndex:12},{value:" to a DOM element. Otherwise BorderBeam cannot locate the real container and the beam cannot be rendered.",paraId:8,tocIndex:12},{value:"The beam layer is positioned with ",paraId:9,tocIndex:12},{value:"position: absolute",paraId:9,tocIndex:12},{value:", so the resolved DOM node also needs to provide a positioning context. In most cases, set ",paraId:9,tocIndex:12},{value:"position: relative",paraId:9,tocIndex:12},{value:" on the wrapped element. BorderBeam does not inspect or patch the child positioning style for you.",paraId:9,tocIndex:12},{value:"For performance reasons, whether ",paraId:10,tocIndex:12},{value:"children",paraId:10,tocIndex:12},{value:" can host the beam and its positioning information are resolved during initialization, and are not continuously updated when the child structure or positioning styles change later.",paraId:10,tocIndex:12},{value:"BorderBeam",paraId:11,tocIndex:13},{value:" reads the computed ",paraId:11,tocIndex:13},{value:"border-radius",paraId:11,tocIndex:13},{value:" from the actual container during initialization. This works best for a single-container child such as ",paraId:11,tocIndex:13},{value:"Card",paraId:11,tocIndex:13},{value:"; for more complex child trees, set the radius on the actual container root for a more deterministic result.",paraId:11,tocIndex:13},{value:"For performance reasons, the radius is not continuously measured after the initial calculation. Later radius changes caused by size, ancestor styles, or internal child state are not guaranteed to resync automatically. The running beam may still apply internal motion smoothing.",paraId:12,tocIndex:13},{value:"For example:",paraId:13,tocIndex:13},{value:"const radius = 24;\n\n<BorderBeam>\n  <Card style={{ borderRadius: radius }} />\n</BorderBeam>;\n",paraId:14,tocIndex:13}];}}]);